-- Thai postal code lookup data for customer intake.
-- Source: thailand-geography-data/thailand-geography-json (MIT License)
-- https://github.com/thailand-geography-data/thailand-geography-json

create table if not exists thai_postal_areas (
  id bigserial primary key,
  postal_code text not null check (postal_code ~ '^[0-9]{5}$'),
  province_th text not null,
  district_th text not null,
  subdistrict_th text not null,
  province_en text,
  district_en text,
  subdistrict_en text,
  province_code integer,
  district_code integer,
  subdistrict_code integer,
  source text not null default 'thailand-geography-json',
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (postal_code, province_th, district_th, subdistrict_th)
);

create index if not exists idx_thai_postal_areas_postal_code on thai_postal_areas(postal_code);
create index if not exists idx_thai_postal_areas_location_th on thai_postal_areas(province_th, district_th, subdistrict_th);

